/**
 * @suppress
 */
public object FfiConverterTypeWhoopCodec: FfiConverter<WhoopCodec, Long> {
    override fun lower(value: WhoopCodec): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): WhoopCodec {
        return WhoopCodec(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): WhoopCodec {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: WhoopCodec) = 8UL

    override fun write(value: WhoopCodec, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



