/**
 * One action the app must take while draining history.
 */
sealed class Step {
    
    /**
     * A decoded record — persist it.
     */
    data class Record(
        val `summary`: uniffi.whoop_ffi.HistorySummary) : Step()
        
    {
        

        companion object
    }
    
    /**
     * A raw 24 Hz optical buffer (v26): a single AC-coupled waveform (no red/IR pair).
     */
    data class Ppg(
        val `unix`: kotlin.UInt, 
        val `recordId`: kotlin.UShort?, 
        val `samples`: List<kotlin.Short>) : Step()
        
    {
        

        companion object
    }
    
    /**
     * A raw 6-axis IMU buffer (v21): 100 Hz accel + gyro, interleaved x,y,z per sample (raw i16 LSB —
     * scale accel by 1/4096 for g, gyro by 2000/32768 for deg/s).
     */
    data class Imu(
        val `unix`: kotlin.UInt, 
        val `sampleRateHz`: kotlin.UShort, 
        val `accel`: List<kotlin.Short>, 
        val `gyro`: List<kotlin.Short>) : Step()
        
    {
        

        companion object
    }
    
    /**
     * A raw multi-wavelength optical buffer (v20): ~25 Hz × 6 channels, raw 20-bit signed ADC counts,
     * flattened channel-major (25 samples of ch0, then ch1, …). Channels [0,1] green, [2,3] ambient,
     * [4,5] red/IR (inferred). SpO2 % is not here — it rides the v18 summary.
     */
    data class Optical(
        val `unix`: kotlin.UInt, 
        val `sampleRateHz`: kotlin.UShort, 
        val `channels`: kotlin.UByte, 
        val `samples`: List<kotlin.Int>) : Step()
        
    {
        

        companion object
    }
    
    /**
     * Write these bytes (confirmed) to the command characteristic — the mandatory HISTORY_END ACK.
     */
    data class Ack(
        val `frame`: kotlin.ByteArray) : Step()
        
    {
        

        companion object
    }
    
    /**
     * The drain finished.
     */
    object Complete : Step()
    
    

    

    
    


    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeStep : FfiConverterRustBuffer<Step>{
    override fun read(buf: ByteBuffer): Step {
        return when(buf.getInt()) {
            1 -> Step.Record(
                FfiConverterTypeHistorySummary.read(buf),
                )
            2 -> Step.Ppg(
                FfiConverterUInt.read(buf),
                FfiConverterOptionalUShort.read(buf),
                FfiConverterSequenceShort.read(buf),
                )
            3 -> Step.Imu(
                FfiConverterUInt.read(buf),
                FfiConverterUShort.read(buf),
                FfiConverterSequenceShort.read(buf),
                FfiConverterSequenceShort.read(buf),
                )
            4 -> Step.Optical(
                FfiConverterUInt.read(buf),
                FfiConverterUShort.read(buf),
                FfiConverterUByte.read(buf),
                FfiConverterSequenceInt.read(buf),
                )
            5 -> Step.Ack(
                FfiConverterByteArray.read(buf),
                )
            6 -> Step.Complete
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: Step): ULong = when(value) {
        is Step.Record -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterTypeHistorySummary.allocationSize(value.`summary`)
            )
        }
        is Step.Ppg -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterUInt.allocationSize(value.`unix`)
                + FfiConverterOptionalUShort.allocationSize(value.`recordId`)
                + FfiConverterSequenceShort.allocationSize(value.`samples`)
            )
        }
        is Step.Imu -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterUInt.allocationSize(value.`unix`)
                + FfiConverterUShort.allocationSize(value.`sampleRateHz`)
                + FfiConverterSequenceShort.allocationSize(value.`accel`)
                + FfiConverterSequenceShort.allocationSize(value.`gyro`)
            )
        }
        is Step.Optical -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterUInt.allocationSize(value.`unix`)
                + FfiConverterUShort.allocationSize(value.`sampleRateHz`)
                + FfiConverterUByte.allocationSize(value.`channels`)
                + FfiConverterSequenceInt.allocationSize(value.`samples`)
            )
        }
        is Step.Ack -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterByteArray.allocationSize(value.`frame`)
            )
        }
        is Step.Complete -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
    }

    override fun write(value: Step, buf: ByteBuffer) {
        when(value) {
            is Step.Record -> {
                buf.putInt(1)
                FfiConverterTypeHistorySummary.write(value.`summary`, buf)
                Unit
            }
            is Step.Ppg -> {
                buf.putInt(2)
                FfiConverterUInt.write(value.`unix`, buf)
                FfiConverterOptionalUShort.write(value.`recordId`, buf)
                FfiConverterSequenceShort.write(value.`samples`, buf)
                Unit
            }
            is Step.Imu -> {
                buf.putInt(3)
                FfiConverterUInt.write(value.`unix`, buf)
                FfiConverterUShort.write(value.`sampleRateHz`, buf)
                FfiConverterSequenceShort.write(value.`accel`, buf)
                FfiConverterSequenceShort.write(value.`gyro`, buf)
                Unit
            }
            is Step.Optical -> {
                buf.putInt(4)
                FfiConverterUInt.write(value.`unix`, buf)
                FfiConverterUShort.write(value.`sampleRateHz`, buf)
                FfiConverterUByte.write(value.`channels`, buf)
                FfiConverterSequenceInt.write(value.`samples`, buf)
                Unit
            }
            is Step.Ack -> {
                buf.putInt(5)
                FfiConverterByteArray.write(value.`frame`, buf)
                Unit
            }
            is Step.Complete -> {
                buf.putInt(6)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}





